// Validate employee onboarding form data
const formData = $input.first().json.body;

const required = ['employee_id', 'full_name', 'email', 'designation', 'date_of_joining', 'ctc_annual'];
const missing = required.filter(f => !formData[f]);

if (missing.length > 0) {
  return [{
    json: {
      success: false,
      error: `Missing required fields: ${missing.join(', ')}`
    }
  }];
}

// Generate employee ID if not provided
if (!formData.employee_id) {
  const timestamp = Date.now().toString(36).toUpperCase();
  formData.employee_id = `EMP${timestamp.substring(0, 6)}`;
}

// Calculate monthly components
const ctc = parseFloat(formData.ctc_annual);
const monthly = ctc / 12;

return [{
  json: {
    success: true,
    data: {
      employee_id: formData.employee_id,
      full_name: formData.full_name,
      designation: formData.designation,
      department: formData.department || 'General',
      email: formData.email.toLowerCase(),
      phone: formData.phone || '',
      date_of_joining: formData.date_of_joining,
      pan_number: formData.pan_number || '',
      bank_name: formData.bank_name || '',
      bank_account: formData.bank_account || '',
      ifsc_code: formData.ifsc_code || '',
      ctc_annual: ctc,
      basic_salary: monthly * 0.4,
      hra: monthly * 0.2,
      conveyance: monthly * 0.05,
      medical: monthly * 0.05,
      special_allowance: monthly * 0.3,
      team_id: formData.team_id || '',
      is_active: true,
      created_at: new Date().toISOString()
    }
  }
}]

